import { ref, reactive, onActivated, onMounted, nextTick } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { MsgBox } from '@/util/msgutil/msgBox.js'
import { Plus, Edit, Delete, Document } from '@element-plus/icons-vue'
import { request } from '@/util/globalContext'
import { listCommon } from '@/util/vueutil/commonList.js'

const PAYMENT_MODE_OPTIONS = [
    { code: '0', label: '月付' },
    { code: '1', label: '季付' },
    { code: '2', label: '年付' }
]

const FEE_MODE_OPTIONS = [
    { code: '0', label: '固定收费' },
    { code: '1', label: '按使用量收费' }
]

const CONTRACT_STATUS_OPTIONS = [
    { code: '0', label: '待生效' },
    { code: '1', label: '生效中' },
    { code: '2', label: '已完成' },
    { code: '3', label: '提前退租' }
]

const DEPOSIT_STATUS_OPTIONS = [
    { code: '0', label: '有效' },
    { code: '1', label: '已退' },
    { code: '2', label: '不退' }
]

export default function useRentContractList() {
    const listRef = ref(null)
    const dialogVisible = ref(false)
    const dialogType = ref('add')
    const formRef = ref(null)

    const Options = ref({
        paymentModeOptions: PAYMENT_MODE_OPTIONS,
        feeModeOptions: FEE_MODE_OPTIONS,
        contractStatusOptions: CONTRACT_STATUS_OPTIONS,
        depositStatusOptions: DEPOSIT_STATUS_OPTIONS
    })

    const searchForm = reactive({
        houseInfo: '',
        tenantName: '',
        dateRange: []
    })

    const {
        oneShow,
        listShow,
        handleReset,
        handleSelectionChange,
        handleCurrentRowChange
    } = listCommon(searchForm)

    const FORM_DEFAULT = {
        id: '',
        contractNo: '',
        houseInfo: '',
        contractSignDate: '',
        rentStartDate: '',
        rentEndDate: '',
        rentDueDay: '',
        monthlyRent: '',
        monthlyWaterFee: '',
        monthlyElectricityFee: '',
        monthlyMiscFee: '',
        waterPrice: '',
        electricityPrice: '',
        paymentMode: '0',
        feeMode: '0',
        depositAmount: '',
        depositStatus: '0',
        contractStatus: '0',
        actualTerminateDate: '',
        tenantName: '',
        tenantPhone: '',
        remark: ''
    }

    const formData = reactive({ ...FORM_DEFAULT })

    const formRules = {
        rentStartDate: [
            { required: true, message: '请选择租房开始日期', trigger: 'change' }
        ],
        rentEndDate: [
            { required: true, message: '请选择租房结束日期', trigger: 'change' }
        ],
        monthlyRent: [
            { required: true, message: '请输入月租金', trigger: 'blur,change' }
        ],
        paymentMode: [
            { required: true, message: '请选择付款模式', trigger: 'change' }
        ],
        feeMode: [
            { required: true, message: '请选择收费模式', trigger: 'change' }
        ]
    }

    const getStatusType = (status) => {
        switch (status) {
            case '0': return 'warning'
            case '1': return 'success'
            case '2': return 'info'
            case '3': return 'danger'
            default: return ''
        }
    }

    const handleLoadList = async (paginationParams) => {
        if (!listRef.value) return
        if (!listRef.value.isInited) {
            await nextTick()
            if (!listRef.value?.isInited) {
                ElMessage.warning('列表组件初始化中，请稍后重试')
                return
            }
        }

        listRef.value?.setLoading(true)
        try {
            const params = {
                ...paginationParams,
                houseInfo: searchForm.houseInfo,
                tenantName: searchForm.tenantName
            }
            const res = await request.get('/rent/contract/getPage', { params })
            if (listRef.value) {
                if (res.code === 200) {
                    listRef.value.updateListData(res.data.records || [])
                    listRef.value.updatePagination({
                        pageNum: paginationParams.pageNum,
                        pageSize: paginationParams.pageSize,
                        total: res.data.total || 0
                    })
                } else {
                    ElMessage.error('列表加载失败：' + (res.msg || '接口异常'))
                    listRef.value.updateListData([])
                    listRef.value.updatePagination({ ...paginationParams, total: 0 })
                }
            }
        } catch (error) {
            ElMessage.error('列表加载失败：网络异常')
            if (listRef.value) {
                listRef.value.updateListData([])
                listRef.value.updatePagination({ ...paginationParams, total: 0 })
            }
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleAdd = () => {
        dialogType.value = 'add'
        formRef.value?.resetFields()
        Object.assign(formData, JSON.parse(JSON.stringify(FORM_DEFAULT)))
        dialogVisible.value = true
    }

    const handleEdit = async () => {
        if (!oneShow.value) {
            ElMessage.warning('请先选中一条数据！')
            return
        }
        if (!listRef.value?.isInited) {
            ElMessage.warning('列表组件初始化中，请稍后重试')
            return
        }

        try {
            listRef.value?.setLoading(true)
            const res = await request.get('/rent/contract/getDetail', { params: { id: oneShow.value.id } })
            if (res.code !== 200) {
                ElMessage.error(res.msg || '接口异常')
                return
            }
            const data = res.data.contract
            Object.assign(formData, JSON.parse(JSON.stringify(FORM_DEFAULT)))
            formData.id = data.id || ''
            formData.contractNo = data.contractNo || ''
            formData.houseInfo = data.houseInfo || ''
            formData.contractSignDate = data.contractSignDate
            formData.rentStartDate = data.rentStartDate
            formData.rentEndDate = data.rentEndDate
            formData.rentDueDay = data.rentDueDay || ''
            formData.monthlyRent = data.monthlyRent
            formData.monthlyWaterFee = data.monthlyWaterFee
            formData.monthlyElectricityFee = data.monthlyElectricityFee
            formData.monthlyMiscFee = data.monthlyMiscFee
            formData.waterPrice = data.waterPrice
            formData.electricityPrice = data.electricityPrice
            formData.paymentMode = data.paymentMode
            formData.feeMode = data.feeMode
            formData.depositAmount = data.depositAmount
            formData.depositStatus = data.depositStatus
            formData.contractStatus = data.contractStatus
            formData.actualTerminateDate = data.actualTerminateDate
            formData.tenantName = data.tenantName || ''
            formData.tenantPhone = data.tenantPhone || ''
            formData.remark = data.remark || ''

            dialogType.value = 'edit'
            dialogVisible.value = true
        } catch (error) {
            ElMessage.error('获取详情失败：' + error)
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleDelete = async () => {
        if (!oneShow.value) {
            ElMessage.warning('请先选中数据！')
            return
        }
        try {
            await ElMessageBox.confirm(
                '确定删除选中的数据？',
                '删除确认',
                { confirmButtonText: '确定', cancelButtonText: '取消', type: 'warning' }
            )

            listRef.value?.setLoading(true)
            const params = {
                id: oneShow.value.id
            }
            const res = await request.post('/rent/contract/del', params)
            if (listRef.value) {
                if (res.code === 200) {
                    ElMessage.success('删除成功')
                    const pagination = listRef.value.getPagination()
                    handleLoadList(pagination)
                } else {
                    MsgBox.warning2('删除失败：' + (res.msg || '接口异常'))
                }
            }
        } catch (error) {
            if (error !== 'cancel') {
                ElMessage.error('删除失败：网络异常')
            }
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleGenerateRecords = async () => {
        if (!oneShow.value) {
            ElMessage.warning('请先选中一条数据！')
            return
        }
        try {
            await ElMessageBox.confirm(
                '确定生成收租记录？这将先删除该合同下已有的收租记录，然后重新生成。',
                '确认生成',
                { confirmButtonText: '确定', cancelButtonText: '取消', type: 'warning' }
            )

            listRef.value?.setLoading(true)
            const params = {
                id: oneShow.value.id
            }
            const res = await request.post('/rent/contract/generateRecords', params)
            if (listRef.value) {
                if (res.code === 200) {
                    ElMessage.success('生成成功，共生成 ' + res.data + ' 条收租记录')
                } else {
                    MsgBox.warning2('生成失败：' + (res.msg || '接口异常'))
                }
            }
        } catch (error) {
            if (error !== 'cancel') {
                ElMessage.error('生成失败：网络异常')
            }
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleSubmit = async () => {
        if (!formRef.value) return

        const isValid = await new Promise((resolve) => {
            formRef.value.validate((valid) => {
                resolve(valid)
            })
        })
        if (!isValid) return

        const submitData = {
            id: dialogType.value === 'edit' ? formData.id : '',
            houseInfo: formData.houseInfo,
            contractSignDate: formData.contractSignDate,
            rentStartDate: formData.rentStartDate,
            rentEndDate: formData.rentEndDate,
            rentDueDay: formData.rentDueDay,
            monthlyRent: parseFloat(formData.monthlyRent) || 0,
            monthlyWaterFee: parseFloat(formData.monthlyWaterFee) || 0,
            monthlyElectricityFee: parseFloat(formData.monthlyElectricityFee) || 0,
            monthlyMiscFee: parseFloat(formData.monthlyMiscFee) || 0,
            waterPrice: parseFloat(formData.waterPrice) || 0,
            electricityPrice: parseFloat(formData.electricityPrice) || 0,
            paymentMode: formData.paymentMode,
            feeMode: formData.feeMode,
            depositAmount: parseFloat(formData.depositAmount) || 0,
            depositStatus: formData.depositStatus,
            contractStatus: formData.contractStatus,
            actualTerminateDate: formData.actualTerminateDate,
            tenantName: formData.tenantName,
            tenantPhone: formData.tenantPhone,
            remark: formData.remark
        }

        if (dialogType.value === 'edit') {
            submitData.contractNo = formData.contractNo
        }

        listRef.value?.setLoading(true)
        try {
            const res = await request.post('/rent/contract/saveOrUpdate', submitData)
            if (listRef.value) {
                if (res.code === 200) {
                    ElMessage.success(dialogType.value === 'add' ? '新增成功' : '修改成功')
                    dialogVisible.value = false
                    const pagination = listRef.value.getPagination()
                    handleLoadList(pagination)
                } else {
                    const tip = dialogType.value === 'add' ? '新增失败' : '修改失败'
                    ElMessage.error(tip + '：' + (res.msg || '接口异常'))
                }
            }
        } catch (error) {
            ElMessage.error('接口异常：' + error)
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    onMounted(async () => {
        await nextTick()
        setTimeout(() => {
            if (listRef.value?.isInited) {
                const pagination = listRef.value.getPagination()
                handleLoadList(pagination)
            }
        }, 50)
    })

    onActivated(async () => {
        if (listRef.value?.isInited) {
            const pagination = listRef.value.getPagination()
            handleLoadList(pagination)
        }
    })

    return {
        searchForm,
        listRef,
        dialogType,
        formRef,
        oneShow,
        listShow,
        formData,
        formRules,
        Plus, Edit, Delete, Document,
        handleSelectionChange,
        handleCurrentRowChange,
        handleAdd,
        handleEdit,
        handleDelete,
        handleSubmit,
        handleLoadList,
        handleReset,
        dialogVisible,
        Options,
        handleGenerateRecords,
        getStatusType
    }
}
